import { TableRenderer, buildColumns } from '@epdoc/table';

const table = new TableRenderer({
  columns: buildColumns(['id', 'name'], { id: { header: 'ID' }, name: { header: 'Name' } }),
  data: [{ id: 1, name: 'Alice' }]
});
table.print();

patterns.code:
const columns: ColumnRegistry<User> = {
  id: { header: 'ID', align: 'right' },
  name: { header: 'Name', maxWidth: 20 }
};
const table = new TableRenderer({
  columns: buildColumns(['id', 'name'], columns),
  data: users
});

TableRenderer.create<User>()
  .column('id', { header: 'ID', align: 'right' })
  .column('status', {
    header: 'Status',
    color: (_v, row) => row.active ? 0x00ff00 : 0xff0000
  })
  .data(users)
  .padding(4)
  .headerStyle((s) => bold(rgb24(s, 0x58d1eb)))
  .print();

const table = new TableRenderer({
  columns,
  data,
  rowStyles: [
    (s) => bgRgb24(s, 0x1a1a2e),
    (s) => bgRgb24(s, 0x16213e)
  ]
});

const table = new TableRenderer({
  columns,
  data,
  borders: { enabled: true, style: 'light', color: 0x888888 }
});
